"use client"

import React, { createContext, useContext, useState, useEffect } from "react"

interface User {
  id: string
  nickname: string
  avatar: string
  isAdmin: boolean
  isSubscribed: boolean
  daysLeft?: number
  mentor?: string
}

interface UserContextType {
  user: User | null
  updateUser: (updates: Partial<User>) => void
  toggleAdmin: () => void
  toggleSubscription: () => void
}

const UserContext = createContext<UserContextType | undefined>(undefined)

export function UserProvider({ children }: { children: React.ReactNode }) {
  // Initial mock user for development
  const [user, setUser] = useState<User | null>({
    id: "8472",
    nickname: "Dmitry K.",
    avatar: "D",
    isAdmin: false,
    isSubscribed: true,
    daysLeft: 24,
    mentor: "Gatee"
  })

const updateUser = (updates: Partial<User>) => {
    setUser((prev: User | null) => (prev ? { ...prev, ...updates } : null))
  }

  const toggleAdmin = () => {
    setUser((prev: User | null) => (prev ? { ...prev, isAdmin: !prev.isAdmin } : null))
  }

  const toggleSubscription = () => {
    setUser((prev: User | null) => (prev ? { ...prev, isSubscribed: !prev.isSubscribed } : null))
  }
  return (
    <UserContext.Provider value={{ user, updateUser, toggleAdmin, toggleSubscription }}>
      {children}
    </UserContext.Provider>
  )
}

export function useUser() {
  const context = useContext(UserContext)
  if (context === undefined) {
    throw new Error("useUser must be used within a UserProvider")
  }
  return context
}
